'use client';

import SouthIndianChart from '../components/charts/SouthIndianChart';

export default function ChartPage() {
  const chart = {
    planets: [
      { name: 'Sun', rasi: 12 },
      { name: 'Moon', rasi: 10 },
      { name: 'Mars', rasi: 5 },
      { name: 'Venus', rasi: 7 },
    ],
  };

  return (
    <div style={{ padding: 40 }}>
      <h2>South Indian Horoscope</h2>

      <SouthIndianChart planets={chart.planets} />
    </div>
  );
}
